{
  "title": "सिस्टम प्रॉम्प्ट का भूमिका",
  "group": "मूल बातें",
  "options": [
    {
      "text": "इसे पहले प्रक्रिया किया जाता है और उपयोगकर्ता संदेशों की तुलना में इसका अधिक भार होता है।"
    },
    {
      "text": "यह उपयोगकर्ता संदेश के समान है लेकिन अलग तरीके से प्रदर्शित किया जाता है।"
    },
    {
      "text": "यह केवल API कॉल के लिए उपयोग किया जाता है, चैट इंटरफ़ेस नहीं।"
    },
    {
      "text": "यह सत्रों के माध्यम से बना रहता है जैसे लंबे समय तक स्मृति।"
    }
  ],
  "questionProse": [
    "संदेशों के ऐरे में `system` भूमिका का उपयोग करने का व्यावहारिक प्रभाव क्या है `user` भूमिका के विपरीत?"
  ],
  "explanationProse": [
    "सिस्टम भूमिका को उच्च प्राथमिकता निर्देशों के रूप में प्रक्रिया किया जाता है। मॉडलों को उपयोगकर्ता संदेशों की तुलना में इसका अधिक भार देने के लिए प्रशिक्षित किया गया है — यह वास्तविक सीमा है \"विकासकर्ता ने क्या कहा\" और \"उपयोगकर्ता ने क्या कहा\" के बीच।\n\nयह जादू नहीं है। यह निश्चित रूप से मॉडल के विरोधाभासी उपयोगकर्ता निर्देशों को अनदेखा करने की गारंटी नहीं देता (देखें: प्रॉम्प्ट इंजेक्शन)। लेकिन यह मॉडल के आपके निर्देशों का अनुसरण करने की प्रवृत्ति को महत्वपूर्ण रूप से बढ़ाता है, विशेष रूप से मजबूत निर्देशों के मॉडलों पर।\n\nअभ्यास में: `system` में अपना पर्सना, नियम और व्यवहारिक प्रतिबंध डालें। `user` में पुनर्प्राप्त संदर्भ और उपयोगकर्ता डेटा डालें। कभी भी उपयोगकर्ता-नियंत्रित इनपुट को `system` में डालें नहीं।"
  ]
}
